import React from "react";

import Box from "@mui/material/Box";
import Typography from "@mui/material/Typography";

import Content from "@/registry/layout/layout-core/Content";
import Footer from "@/registry/layout/layout-core/Footer";
import Header from "@/registry/layout/layout-core/Header";
import InsetContent from "@/registry/layout/layout-core/InsetContent";
import InsetSidebar from "@/registry/layout/layout-core/InsetSidebar";
import Root from "@/registry/layout/layout-core/Root";

export const meta = {
  title: "Inset Sidebar Sticky",
  description:
    "Default sticky behavior — sidebar sticks under the header on scroll.",
  previewMode: "iframe",
};

export function Demo() {
  return (
    <Root height="300px" sx={{ maxHeight: "400px" }}>
      <Header>
        <Box sx={{ px: 2 }}>
          <Typography variant="caption" fontWeight="bold">
            Header
          </Typography>
        </Box>
      </Header>
      <Content>
        <Box sx={{ p: 2, flex: 1 }}>
          {Array.from({ length: 100 }, (_, i) => (
            <Typography key={i} variant="body2" color="text.secondary">
              Line {i + 1}
            </Typography>
          ))}
        </Box>
        <InsetSidebar width="200px">
          <InsetContent>
            <Box sx={{ p: 2 }}>
              <Typography variant="caption" color="text.secondary">
                Sticky sidebar — scroll main content to see
              </Typography>
            </Box>
          </InsetContent>
        </InsetSidebar>
      </Content>
      <Footer>
        <Box sx={{ p: 2 }}>
          <Typography variant="caption" color="text.secondary">
            Footer
          </Typography>
        </Box>
      </Footer>
    </Root>
  );
}
